// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [selectedDayIndex, setSelectedDayIndex] = useState<number>(0);
  const [showDetails, setShowDetails] = useState<boolean>(true);

  const normalizedCondition = useMemo(() => props.condition.toLowerCase(), [props.condition]);

  const currentIcon = useMemo(() => {
    if (normalizedCondition.includes('sun') || normalizedCondition.includes('clear')) return '☀️';
    if (normalizedCondition.includes('cloud') || normalizedCondition.includes('overcast')) return '☁️';
    if (normalizedCondition.includes('rain') || normalizedCondition.includes('drizzle') || normalizedCondition.includes('shower')) return '🌧️';
    if (normalizedCondition.includes('storm') || normalizedCondition.includes('thunder')) return '⛈️';
    if (normalizedCondition.includes('snow') || normalizedCondition.includes('sleet') || normalizedCondition.includes('blizzard')) return '❄️';
    if (normalizedCondition.includes('mist') || normalizedCondition.includes('fog') || normalizedCondition.includes('haze')) return '🌫️';
    return '🌤️';
  }, [normalizedCondition]);

  const safeForecast = useMemo(() => (Array.isArray(props.forecast) ? props.forecast : []), [props.forecast]);

  const selectedForecast = useMemo(() => {
    if (safeForecast.length === 0) return null;
    return safeForecast[Math.min(selectedDayIndex, safeForecast.length - 1)] ?? null;
  }, [safeForecast, selectedDayIndex]);

  useEffect(() => {
    if (selectedDayIndex > safeForecast.length - 1) {
      setSelectedDayIndex(0);
    }
  }, [safeForecast, selectedDayIndex]);

  const getForecastIcon = useCallback((icon?: string) => {
    if (!icon) return '🌤️';
    const v = icon.toLowerCase();
    if (v.includes('sun') || v.includes('clear')) return '☀️';
    if (v.includes('cloud') || v.includes('overcast')) return '☁️';
    if (v.includes('rain') || v.includes('drizzle') || v.includes('shower')) return '🌧️';
    if (v.includes('storm') || v.includes('thunder')) return '⛈️';
    if (v.includes('snow') || v.includes('sleet')) return '❄️';
    if (v.includes('fog') || v.includes('mist') || v.includes('haze')) return '🌫️';
    return icon;
  }, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" radius="xl">
        <Stack gap="var(--ggui-spacing-6)">
          <Row justify="between" align="start" wrap>
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              <Row align="center" gap="var(--ggui-spacing-2)">
                <Text size="4xl" weight="bold" color="var(--ggui-color-primary-700)">
                  {props.temperature}°{props.unit}
                </Text>
                <Text size="3xl" is="span" aria-label={props.condition}>
                  {currentIcon}
                </Text>
              </Row>
              <Row align="center" gap="var(--ggui-spacing-2)">
                <Badge variant="primary">{props.condition}</Badge>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  {showDetails ? 'Details visible' : 'Details hidden'}
                </Text>
              </Row>
            </Stack>

            <Button
              variant="outline"
              onClick={() => setShowDetails(!showDetails)}
            >
              {showDetails ? 'Hide details' : 'Show details'}
            </Button>
          </Row>

          {showDetails && (
            <Row gap="var(--ggui-spacing-4)" wrap>
              <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                  <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
                </Stack>
              </Card>
              <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                  <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} {props.unit === 'F' ? 'mph' : 'km/h'}</Text>
                </Stack>
              </Card>
              {selectedForecast && (
                <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Selected Day</Text>
                    <Text variant="body" weight="medium">
                      {selectedForecast.day ?? 'N/A'} {getForecastIcon(selectedForecast.icon)}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      H: {selectedForecast.high ?? '--'}°{props.unit} / L: {selectedForecast.low ?? '--'}°{props.unit}
                    </Text>
                  </Stack>
                </Card>
              )}
            </Row>
          )}

          <Divider margin="var(--ggui-spacing-1)" />

          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={3} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
            {safeForecast.length === 0 ? (
              <Alert variant="info" title="No forecast available">
                Forecast data is currently unavailable.
              </Alert>
            ) : (
              <Row gap="var(--ggui-spacing-2)" wrap>
                {safeForecast.map((item, index) => (
                  <Card
                    key={`${item.day ?? 'day'}-${index}`}
                    as={Clickable}
                    onClick={() => setSelectedDayIndex(index)}
                    hoverStyle={{
                      background: 'var(--ggui-color-primary-50)',
                      borderColor: 'var(--ggui-color-primary-300)'
                    }}
                    style={{
                      background: selectedDayIndex === index ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                      border: `1px solid ${selectedDayIndex === index ? 'var(--ggui-color-primary-300)' : 'var(--ggui-color-outlineVariant)'}`,
                      outline: selectedDayIndex === index ? '2px solid var(--ggui-color-primary-600)' : 'none',
                      outlineOffset: selectedDayIndex === index ? '2px' : '0'
                    }}
                    aria-pressed={selectedDayIndex === index}
                    padding="var(--ggui-spacing-3)"
                    shadow="sm"
                    radius="lg"
                    border
                  >
                    <Stack align="center" gap="var(--ggui-spacing-1)">
                      <Text
                        variant="caption"
                        weight={selectedDayIndex === index ? 'semibold' : 'normal'}
                        color={selectedDayIndex === index ? 'var(--ggui-color-primary-700)' : 'var(--ggui-color-onSurfaceVariant)'}
                      >
                        {item.day ?? 'N/A'}
                      </Text>
                      <Text size="xl" is="span" aria-label={item.icon ?? 'weather icon'}>
                        {getForecastIcon(item.icon)}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurface)">
                        {item.high ?? '--'}° / {item.low ?? '--'}°
                      </Text>
                    </Stack>
                  </Card>
                ))}
              </Row>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>

  );
}

