interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}


const categoryColor = (category?: string): string => {
  const key = (category || 'unknown').toLowerCase();
  if (key.includes('alkali')) return 'var(--ggui-color-error-100)';
  if (key.includes('alkaline')) return 'var(--ggui-color-warning-100)';
  if (key.includes('transition')) return 'var(--ggui-color-primary-100)';
  if (key.includes('post-transition')) return 'var(--ggui-color-info-100)';
  if (key.includes('metalloid')) return 'var(--ggui-color-success-100)';
  if (key.includes('nonmetal')) return 'var(--ggui-color-primary-50)';
  if (key.includes('halogen')) return 'var(--ggui-color-warning-100)';
  if (key.includes('noble')) return 'var(--ggui-color-info-100)';
  if (key.includes('lanthanide')) return 'var(--ggui-color-success-100)';
  if (key.includes('actinide')) return 'var(--ggui-color-error-100)';
  return 'var(--ggui-color-surfaceVariant)';
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const normalizedElements = useMemo(() => {
    return (props.elements || []).map((element, index) => ({
      atomicNumber: element.atomicNumber ?? index + 1,
      symbol: element.symbol ?? '',
      name: element.name ?? 'Unknown',
      atomicWeight: element.atomicWeight ?? 0,
      category: element.category ?? 'Unknown',
      row: element.row ?? 1,
      col: element.col ?? 1,
    }));
  }, [props.elements]);

  const filteredElements = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return normalizedElements;
    return normalizedElements.filter((element) => {
      return element.name.toLowerCase().includes(q) || element.symbol.toLowerCase().includes(q);
    });
  }, [normalizedElements, query]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    return normalizedElements.find((element) => element.atomicNumber === selectedAtomicNumber) || null;
  }, [normalizedElements, selectedAtomicNumber]);

  useEffect(() => {
    if (!selectedElement && filteredElements.length > 0 && selectedAtomicNumber === null) {
      setSelectedAtomicNumber(filteredElements[0].atomicNumber);
    }
  }, [filteredElements, selectedAtomicNumber, selectedElement]);

  const categories = useMemo(() => {
    const unique = new Map<string, string>();
    normalizedElements.forEach((element) => {
      if (!unique.has(element.category)) {
        unique.set(element.category, categoryColor(element.category));
      }
    });
    return Array.from(unique.entries()).map(([name, color]) => ({ name, color }));
  }, [normalizedElements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Interactive Periodic Table</Heading>

        <Input
          label="Search elements by name or symbol"
          placeholder="Type e.g. Hydrogen or H"
          value={query}
          onChange={setQuery}
          type="search"
        />

        {normalizedElements.length === 0 ? (
          <Alert variant="info" title="No element data">
            No elements are available to display.
          </Alert>
        ) : (
          <>
            <Card padding="var(--ggui-spacing-4)" border shadow="sm">
              {filteredElements.length === 0 ? (
                <Box padding="var(--ggui-spacing-6)">
                  <Text color="var(--ggui-color-onSurfaceVariant)">No elements match your search.</Text>
                </Box>
              ) : (
                <Box style={{ overflowX: 'auto' }}>
                  <Box
                    style={{
                      display: 'grid',
                      gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
                      gap: 'var(--ggui-spacing-2)',
                      minWidth: 'var(--ggui-spacing-12)',
                    }}
                  >
                    {filteredElements.map((element) => (
                      <Card
                        key={element.atomicNumber}
                        as={Clickable}
                        onClick={() => setSelectedAtomicNumber(element.atomicNumber)}
                        padding="var(--ggui-spacing-2)"
                        border
                        shadow={selectedAtomicNumber === element.atomicNumber ? 'md' : 'none'}
                        hoverStyle={{
                          boxShadow: 'var(--ggui-shape-shadow-sm)',
                          transform: 'translateY(-1px)',
                        }}
                        style={{
                          gridColumn: element.col,
                          gridRow: element.row,
                          minHeight: 'var(--ggui-spacing-12)',
                          background: categoryColor(element.category),
                          outline: selectedAtomicNumber === element.atomicNumber ? '2px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outlineVariant)',
                          position: 'relative',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                        }}
                        aria-pressed={selectedAtomicNumber === element.atomicNumber}
                        aria-label={`${element.name} (${element.symbol}), atomic number ${element.atomicNumber}`}
>
                        <Text
                          variant="caption"
                          color="var(--ggui-color-onSurfaceVariant)"
                          is="span"
                          style={{
                            position: 'absolute',
                            top: 'var(--ggui-spacing-1)',
                            left: 'var(--ggui-spacing-1)',
                          }}
>
                          {element.atomicNumber}
                        </Text>
                        <Text size="xl" weight="bold" align="center">{element.symbol}</Text>
                      </Card>
                    ))}
                  </Box>
                </Box>
              )}
            </Card>

            <Card padding="var(--ggui-spacing-4)" border shadow="sm">
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={3}>Element Details</Heading>
                {selectedElement ? (
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text><Text is="span" weight="semibold">Name:</Text> {selectedElement.name}</Text>
                    <Text><Text is="span" weight="semibold">Symbol:</Text> {selectedElement.symbol}</Text>
                    <Text><Text is="span" weight="semibold">Atomic Number:</Text> {selectedElement.atomicNumber}</Text>
                    <Text><Text is="span" weight="semibold">Atomic Weight:</Text> {selectedElement.atomicWeight}</Text>
                    <Text><Text is="span" weight="semibold">Category:</Text> {selectedElement.category}</Text>
                  </Stack>
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant)">Select an element to view details.</Text>
                )}
              </Stack>
            </Card>

            <Card padding="var(--ggui-spacing-4)" border shadow="sm">
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={3}>Legend</Heading>
