    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const [activeTab, setActiveTab] = useState<string>('description');
  const maxStock = Math.max(0, Number(props.product.stock ?? 0));
  const [quantity, setQuantity] = useState<number>(maxStock > 0 ? 1 : 1);

  useEffect(() => {
    if (maxStock > 0) {
      setQuantity((prev) => {
        if (prev < 1) return 1;
        if (prev > maxStock) return maxStock;
        return prev;
      });
    } else {
      setQuantity(1);
    }
  }, [maxStock]);

  const normalizedRating = useMemo(() => {
    const raw = Number(props.product.rating ?? 0);
    if (Number.isNaN(raw)) return 0;
    return Math.min(5, Math.max(0, Math.round(raw)));
  }, [props.product.rating]);

  const priceLabel = useMemo(() => {
    const amount = Number(props.product.price ?? 0);
    const currency = props.product.currency ?? '$';
    return `${currency}${amount.toFixed(2)}`;
  }, [props.product.price, props.product.currency]);

  const stockBadge = useMemo(() => {
    if (maxStock <= 0) return { text: 'Out of Stock', variant: 'error' as const };
    if (maxStock <= 5) return { text: 'Low Stock', variant: 'warning' as const };
    return { text: 'In Stock', variant: 'success' as const };
  }, [maxStock]);

  const specificationRows = useMemo(() => {
    return (Array.isArray(props.product.specifications) ? props.product.specifications : []).map((item, index) => {
      const specItem = item as { key?: string; label?: string; name?: string; value?: string | number };
      const label = specItem.key ?? specItem.label ?? specItem.name ?? `Spec ${index + 1}`;
      const value = specItem.value ?? '';
      return { label: String(label), value: String(value) };
    });
  }, [props.product.specifications]);

  const reviewRows = useMemo(() => {
    return (Array.isArray(props.product.reviews) ? props.product.reviews : []).map((item, index) => {
