        text: review.text ?? '',
        date: review.date ?? '',
      };
    });
  }, [props.product.reviews]);

  const increaseQuantity = useCallback(() => {
    setQuantity((prev) => {
      if (maxStock <= 0) return 1;
      return Math.min(maxStock, prev + 1);
    });
  }, [maxStock]);

  const decreaseQuantity = useCallback(() => {
    setQuantity((prev) => Math.max(1, prev - 1));
  }, []);

