  }, [typing.latest]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messageList.length, typingState?.active]);

  const handleSend = useCallback(() => {
    const trimmed = draft.trim();
    if (!trimmed) return;
    const outgoing = {
      sender: props.currentUser,
      text: trimmed,
      timestamp: new Date().toISOString(),
    };
    setMessageList((prev) => [...prev, outgoing]);
    sendMessage({ text: trimmed, timestamp: outgoing.timestamp as string });
    setDraft('');
  }, [draft, props.currentUser, sendMessage]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    (messageList ?? []).forEach((msg) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === msg.sender) {
        last.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
    return groups;
  }, [messageList]);

