              style={{
                maxHeight: '60vh',
                overflowY: 'auto',
                padding: 'var(--ggui-spacing-2)',
              }}
            >
              <Stack gap="var(--ggui-spacing-3)">
                {groupedMessages.length === 0 ? (
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    No messages yet.
                  </Text>
                ) : (
                  groupedMessages.map((group, groupIndex) => {
                    const isOwnGroup = group.sender === props.currentUser;
                    return (
                      <Stack
                        key={`${group.sender ?? 'unknown'}-${groupIndex}` }
                        gap="var(--ggui-spacing-1)"
                        align={isOwnGroup ? 'end' : 'start'}
                      >
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                          {group.sender ?? 'Unknown'}
                        </Text>
                        {group.items.map((msg, msgIndex) => (
                          <Card
                            key={`${groupIndex}-${msgIndex}-${msg.timestamp ?? 't'}` }
                            padding="var(--ggui-spacing-2)"
                            shadow="none"
                            border={false}
                            radius="md"
                            style={{
                              maxWidth: '75%',
                              background: isOwnGroup
                                ? 'var(--ggui-color-primary-600)'
                                : 'var(--ggui-color-surfaceVariant)',
                            }}
                          >
                            <Stack gap="var(--ggui-spacing-1)">
                              <Text
                                variant="bodySmall"
                                color={isOwnGroup ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                              >
                                {msg.text ?? ''}
                              </Text>
                              <Text
                                variant="caption"
                                color={isOwnGroup ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                                align={isOwnGroup ? 'right' : 'left'}
                              >
                                {msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                              </Text>
                            </Stack>
                          </Card>
                        ))}
                      </Stack>
                    );
                  })
                )}
              </Stack>
            </Box>
          </Box>

          <Divider margin="var(--ggui-spacing-1)" />

          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                placeholder="Type a message..."
                value={draft}
                onChange={setDraft}
                onKeyDown={(event) => {
                  if (event.key === 'Enter') {
                    event.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button
              variant="primary"
              disabled={!draft.trim()}
              as={Clickable}
              onClick={handleSend}
            >
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

