/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [stocksState, setStocksState] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [now, setNow] = useState<Date>(new Date());
  const [flashMap, setFlashMap] = useState<Record<string, boolean>>({});
  const flashTimeoutsRef = useRef<Record<string, ReturnType<typeof setTimeout>>>({});

  useEffect(() => {
    setStocksState(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const update = priceUpdate.latest;
    if (!update || !update.symbol) {
      return;
    }

    setStocksState((prev) => {
      const existing = prev.find((item) => item.symbol === update.symbol);
      if (!existing) {
        return [
          ...prev,
          {
            symbol: update.symbol,
            name: update.symbol,
            price: update.price,
            change: update.change,
            changePercent: update.changePercent,
          },
        ];
      }
      return prev.map((item) => {
        if (item.symbol !== update.symbol) {
          return item;
        }
        return {
          ...item,
          price: update.price ?? item.price,
          change: update.change ?? item.change,
          changePercent: update.changePercent ?? item.changePercent,
        };
      });
    });

    setLastUpdated(new Date());
    setFlashMap((prev) => ({ ...prev, [update.symbol]: true }));
    if (flashTimeoutsRef.current[update.symbol]) {
      clearTimeout(flashTimeoutsRef.current[update.symbol]);
    }
    flashTimeoutsRef.current[update.symbol] = setTimeout(() => {
      setFlashMap((prev) => ({ ...prev, [update.symbol]: false }));
    }, 700);
  }, [priceUpdate.latest]);

  useEffect(() => {
    return () => {
      Object.values(flashTimeoutsRef.current).forEach((timeout) => clearTimeout(timeout));
    };
  }, []);

  const formattedLastUpdated = useMemo(() => lastUpdated.toLocaleTimeString(), [lastUpdated]);
  const formattedClock = useMemo(() => now.toLocaleTimeString(), [now]);

  const marketStatusVariant = useMemo(() => {
    if (marketStatus.latest?.status === 'open') return 'success';
    if (marketStatus.latest?.status === 'closed') return 'error';
    return 'warning';
  }, [marketStatus.latest?.status]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={1} color="var(--ggui-color-onSurface)">Market Watch</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" is="div" aria-live="polite" aria-atomic>
                Last Updated: {formattedLastUpdated}
              </Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" is="div" aria-live="polite" aria-atomic>
                Live Clock: {formattedClock}
              </Text>
            </Stack>
            <Row gap="var(--ggui-spacing-2)" align="center" wrap>
              <Badge variant={marketStatusVariant}>
                {marketStatus.latest?.status ? `Market ${marketStatus.latest.status}` : 'Market status unavailable'}
              </Badge>
              {marketStatus.latest?.timestamp ? (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {new Date(marketStatus.latest.timestamp).toLocaleString()}
                </Text>
              ) : null}
            </Row>
          </Row>
        </Card>

        {stocksState.length === 0 ? (
          <Alert variant="info" title="No stock data">
            No stocks available to display right now.
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stocksState.map((stock, index) => {
              const symbol = stock.symbol ?? `STK-${index}`;
              const isPositive = (stock.change ?? 0) >= 0;
              const directionArrow = isPositive ? '▲' : '▼';
              const valueColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
              const borderColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';

              return (
                <Box
                  key={symbol}
                  padding="var(--ggui-spacing-1)"
                  background={flashMap[symbol] ? 'var(--ggui-color-primary-50)' : 'transparent'}
                  borderRadius="var(--ggui-shape-radius-lg)"
                >
                  <Card
                    padding="var(--ggui-spacing-4)"
                    shadow="sm"
                    border
                    style={{ borderColor }}
                  >
                    <Stack gap="var(--ggui-spacing-3)">
                      <Row justify="between" align="start">
                        <Stack gap="var(--ggui-spacing-1)">
                          <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
                            {stock.symbol ?? '—'}
                          </Text>
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                            {stock.name ?? 'Unknown Company'}
                          </Text>
                        </Stack>
                        <Box
                          paddingX="var(--ggui-spacing-2)"
                          paddingY="var(--ggui-spacing-1)"
                          background="var(--ggui-color-surfaceVariant)"
                          borderRadius="var(--ggui-shape-radius-full)"
                        >
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            {marketStatus.latest?.status ?? 'live'}
                          </Text>
                        </Box>
                      </Row>

                      <Divider margin="var(--ggui-spacing-1)" />

                      <Row justify="between" align="end">
                        <Stack gap="var(--ggui-spacing-1)">
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Price</Text>
                          <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">
                            ${(stock.price ?? 0).toFixed(2)}
                          </Text>
                        </Stack>
                        <Stack gap="var(--ggui-spacing-1)" align="end">
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Change</Text>
                          <Text weight="semibold" color={valueColor}>
                            {(stock.change ?? 0) >= 0 ? '+' : ''}{(stock.change ?? 0).toFixed(2)}
                          </Text>
                          <Text weight="semibold" color={valueColor} is="div" aria-live="polite" aria-atomic>
                            {directionArrow} {(stock.changePercent ?? 0) >= 0 ? '+' : ''}{(stock.changePercent ?? 0).toFixed(2)}%
                          </Text>
                        </Stack>
                      </Row>

                      <Box
                        padding="var(--ggui-spacing-1)"
                        background="var(--ggui-color-surfaceVariant)"
                        borderRadius="var(--ggui-shape-radius-md)"
                      >
                        <Box
                          padding="var(--ggui-spacing-1)"
                          borderRadius="var(--ggui-shape-radius-sm)"
                          background={borderColor}
                        >
                          <Text variant="caption" color="var(--ggui-color-surface)">
                            Trend: {isPositive ? 'Positive momentum' : 'Negative momentum'}
                          </Text>
                        </Box>
                      </Box>
                    </Stack>
                  </Card>
                </Box>
              );
            })}
          </CardGrid>
        )}
