export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar ?? (props.avatarOptions[0] ?? '😀'));
  const [role, setRole] = useState(props.initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme ?? 'light');
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isEmailValid = emailRegex.test(email.trim());
  const isStep1Valid = name.trim().length > 0 && isEmailValid && avatar.trim().length > 0;
  const isStep2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');
  const canGoNext = (step === 1 && isStep1Valid) || (step === 2 && isStep2Valid);
  const progressValue = step * 33.3333;

  useEffect(() => {
    setName(props.initialProfile.name ?? '');
    setEmail(props.initialProfile.email ?? '');
    setAvatar(props.initialProfile.avatar ?? (props.avatarOptions[0] ?? '😀'));
    setRole(props.initialProfile.role ?? '');
    setEmailNotifications(props.initialProfile.emailNotifications ?? true);
    setTheme(props.initialProfile.theme ?? 'light');
  }, [props.initialProfile, props.avatarOptions]);

  const handleNext = useCallback(() => {
    if (step < 3 && canGoNext) {
      setStep(step + 1);
    }
  }, [step, canGoNext]);

  const handleBack = useCallback(() => {
    if (step > 1) {
      setStep(step - 1);
    }
  }, [step]);

  const handleComplete = useCallback(() => {
    if (!isStep1Valid || !isStep2Valid) return;
    complete({ name: name.trim(), email: email.trim(), avatar, role, emailNotifications, theme });
  }, [complete, name, email, avatar, role, emailNotifications, theme, isStep1Valid, isStep2Valid]);

  return (
