            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Setup</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="md" border>
          <Box>
            {step === 1 && (
              <Box>
                <Stack gap="var(--ggui-spacing-4)">
                  <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                    <Heading level={4}>Profile Setup</Heading>
                    <Text color="var(--ggui-color-onSurfaceVariant)">Set up your identity to get started.</Text>
                  </Box>
                  <Input
                    label="Name"
                    value={name}
                    onChange={setName}
                    placeholder="Enter your full name"
                    required
                    error={name.trim().length === 0 ? 'Name is required.' : undefined}
                  />
                  <Input
                    label="Email"
                    type="email"
                    value={email}
                    onChange={setEmail}
                    placeholder="you@example.com"
                    required
                    error={email.trim().length === 0 ? 'Email is required.' : (!isEmailValid ? 'Please enter a valid email address.' : undefined)}
                  />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label">Choose Avatar</Text>
                    <Row gap="var(--ggui-spacing-2)" wrap>
                      {(props.avatarOptions && props.avatarOptions.length > 0 ? props.avatarOptions.slice(0, 4) : ['😀', '😎', '🚀', '🎨']).map((option) => (
                        <Card
                          key={option}
                          as={Clickable}
                          onClick={() => setAvatar(option)}
                          padding="var(--ggui-spacing-3)"
                          border
                          shadow="none"
                          radius="md"
                          style={{
                            borderColor: avatar === option ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                            background: avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                            transition: 'all 200ms ease'
                          }}
                        >
                          <Text size="2xl" align="center">{option}</Text>
                        </Card>
                      ))}
                    </Row>
                  </Stack>
                </Stack>
              </Box>
            )}

            {step === 2 && (
              <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Preferences</Heading>
                  <Select
                    label="Role"
                    value={role}
                    onChange={setRole}
                    placeholder="Select your role"
                    options={(props.roleOptions && props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other']).map((option) => ({ value: option, label: option }))}
                    required
                    error={role.trim().length === 0 ? 'Please select a role.' : undefined}
                  />
                  <Toggle
                    label="Email notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                  />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label">Theme preference</Text>
                    <Row gap="var(--ggui-spacing-3)">
                      <Card as={Clickable} onClick={() => setTheme('light')} padding="var(--ggui-spacing-3)" border shadow="none" style={{ borderColor: theme === 'light' ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)' }}><Text>☀️ Light</Text></Card>
                      <Card as={Clickable} onClick={() => setTheme('dark')} padding="var(--ggui-spacing-3)" border shadow="none" style={{ borderColor: theme === 'dark' ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)' }}><Text>🌙 Dark</Text></Card>
                    </Row>
                  </Stack>
                </Stack>
              </Box>
            )}

            {step === 3 && (
              <Box style={{ animation: 'ggui-fadeIn 200ms ease-out' }}>
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Review & Confirm</Heading>
                  <Text color="var(--ggui-color-onSurfaceVariant)">Please review your details before completing setup.</Text>
                  <Card padding="var(--ggui-spacing-4)" border shadow="none">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                      <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                      <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar || '-'}</Text></Row>
                      <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                      <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                      <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                    </Stack>
                  </Card>
                </Stack>
              </Box>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-4)" />
          <Row justify="between" align="center">
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>Back</Button>
            <Row gap="var(--ggui-spacing-2)">
              {step < 3 && (
                <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>Next</Button>
              )}
              {step === 3 && (
                <>
                  <Button variant="outline" onClick={() => setStep(2)}>Go Back</Button>
                  <Button variant="primary" onClick={handleComplete} disabled={!isStep1Valid || !isStep2Valid}>Complete Setup</Button>
                </>
              )}
            </Row>
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
